#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    std::string toString() const {
        std::stringstream ss;
        ss << std::fixed << std::setprecision(1);
        ss << real;
        if (imaginary >= 0) {
            ss << " + " << imaginary << "i";
        } else {
            ss << " - " << -imaginary << "i";
        }
        return ss.str();
    }

    ComplexNumber operator-() const {
        return ComplexNumber(-real, -imaginary);
    }
};

int main() {
    ComplexNumber c1(3.5, -2.0);
    ComplexNumber negated_c1 = -c1;
    std::cout << negated_c1.toString() << std::endl;

    ComplexNumber c2(-1.0, 4.0);
    ComplexNumber negated_c2 = -c2;
    std::cout << negated_c2.toString() << std::endl;

    ComplexNumber c3(0.0, 0.0);
    ComplexNumber negated_c3 = -c3;
    std::cout << negated_c3.toString() << std::endl;

    ComplexNumber c4(10.0, 0.0);
    ComplexNumber negated_c4 = -c4;
    std::cout << negated_c4.toString() << std::endl;

    ComplexNumber c5(0.0, -5.5);
    ComplexNumber negated_c5 = -c5;
    std::cout << negated_c5.toString() << std::endl;

    return 0;
}
